import React from "react";
import Icon from "../assets/gem.png";

function Footer() {
  return (
    <footer className="bg-gray-100 text-gray-700 border-t border-gray-200 mt-auto">
      <div className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-6">
          {/* Logo */}
          <a href="/" className="flex items-center gap-3">
            <img src={Icon} className="h-8" alt="GemAnalyzer Logo" />
            <span className="text-xl font-bold text-blue-700">GemAnalyzer</span>
          </a>

          {/* Links */}
          <ul className="flex flex-wrap gap-6 text-sm font-medium">
            <li><a href="/" className="hover:text-blue-600 transition">Home</a></li>
            <li><a href="/about" className="hover:text-blue-600 transition">About</a></li>
            <li><a href="/instructions" className="hover:text-blue-600 transition">Instructions</a></li>
            <li><a href="/imageuploader" className="hover:text-blue-600 transition">Analyse</a></li>
          </ul>
        </div>

        <div className="mt-8 text-center text-sm text-gray-500">
          © 2026 GemAnalyzer. All Rights Reserved.
        </div>
      </div>
    </footer>
  );
}

export default Footer;
